    "failure_modes": [
      {
        "scenario": "Payment gateway slow (5-8s response times)",
        "handling": "unhandled",
        "recommendation": "CRITICAL: CartService kills connection at 5s, but gateway processes payment at 7s. Customer is charged, but CartService returns failure. No reconciliation exists. FIX: Either (1) set CartService→PaymentService timeout > PaymentService→Gateway timeout, or (2) add a payment status reconciliation job, or (3) use async payment confirmation with webhooks."
      },
      {
        "scenario": "OrderService down or slow",
        "handling": "unhandled",
        "recommendation": "No circuit breaker on OrderService means CartService will keep sending requests during an outage, compounding the failure. Add a circuit breaker with appropriate thresholds."
      },
      {
        "scenario": "PaymentService fails after OrderService succeeds",
        "handling": "unhandled",
        "recommendation": "CRITICAL: Order is created, inventory is reserved, but payment fails. No compensation. Implement a saga pattern: on payment failure, call OrderService to cancel the order and release inventory. Alternatively, reverse the order — authorize payment first, then create the order."
      },
      {
        "scenario": "InventoryService timeout causes OrderService to exceed CartService timeout",
        "handling": "partial",
        "recommendation": "OrderService retry budget (3s + 3s = 6s) exceeds CartService timeout (5s). Cap OrderService total timeout (including retries) to 4s to leave margin. Consider: 2s initial + 2s retry = 4s max."
      },
      {
        "scenario": "CartService circuit breaker opens on PaymentService",
        "handling": "partial",
        "recommendation": "Circuit breaker prevents calls to PaymentService for 30s. During this window, ALL checkouts fail instantly — but orders may still be created if the call to OrderService happens first. Reorder the calls or short-circuit the entire flow when the breaker is open."
