        "Compensation/saga event queue for order rollback on payment failure",
        "Payment reconciliation queue"
      ],
      "config_changes": [
        "Fix CartService→PaymentService timeout to exceed 8s (e.g., 10s)",
        "Cap OrderService retry budget to fit within CartService timeout (e.g., 2s + 2s)",
        "Add circuit breaker config for CartService→OrderService",
        "Add circuit breaker config for PaymentService→PaymentGateway"
      ],
      "infra_provisioning": []
    },
