      "data_preserving": false,
      "large_table_impact": false,
      "details": "Not assessed — no schema information provided. However, orphaned orders and reserved-but-unused inventory will accumulate in the database without a cleanup mechanism."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
